import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

function EmployeeOffers() {
  const navigate = useNavigate();

  const [offers, setOffers] = useState([]);

  // Logged-in employee
  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || null;

  /* ---------------- LOAD OFFERS ---------------- */
  useEffect(() => {
    if (!loggedUser) return;

    const allOffers =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    // 🔥 Filter only this employee's offers
    const myOffers = allOffers.filter(
      (o) => o.email === loggedUser.email
    );

    setOffers(myOffers);
  }, [loggedUser]);

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>My Job Offers</h2>

      {offers.length === 0 ? (
        <p>No offers received yet.</p>
      ) : (
        <table className="designation-table">
          <thead>
            <tr>
              <th>S.No</th>
              <th>Job Title</th>
              <th>Salary</th>
              <th>Location</th>
              <th>Joining Date</th>
              <th>Offer Date</th>
              <th>Action</th>
            </tr>
          </thead>

          <tbody>
            {offers.map((o, i) => (
              <tr key={o.applicationId}>
                <td>{i + 1}</td>
                <td>{o.jobTitle}</td>
                <td>₹{o.salary}</td>
                <td>{o.location}</td>
                <td>{o.joiningDate}</td>
                <td>{o.offerDate}</td>

                <td>
                  <button
                    onClick={() =>
                      navigate(
                        `/dashboard/recruitment/offer-preview/${o.applicationId}`
                      )
                    }
                  >
                    View Offer
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default EmployeeOffers;
